package com.example.app

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import androidx.activity.result.ActivityResultLauncher
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import androidx.core.content.edit

class LoginActivity : AppCompatActivity() {

    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_AUTHENTICATED = "key_authenticated"
        private const val KEY_USERNAME = "key_username"
        private const val KEY_PASSWORD = "key_password"
    }

    private lateinit var prefs: SharedPreferences
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    private lateinit var usernameEditText: EditText
    private lateinit var passwordEditText: EditText
    private lateinit var loginButton: Button
    private lateinit var biometricButton: Button

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        if (prefs.getBoolean(KEY_AUTHENTICATED, false)) {
            goToHome()
            return
        }

        usernameEditText = findViewById(R.id.usernameEditText)
        passwordEditText = findViewById(R.id.passwordEditText)
        loginButton = findViewById(R.id.loginButton)
        biometricButton = findViewById(R.id.biometricButton)

        setupBiometricPrompt()

        loginButton.setOnClickListener {
            performPasswordLogin()
        }

        biometricButton.setOnClickListener {
            startBiometricAuth()
        }

        checkBiometricAvailabilityAndPrefill()
    }

    private fun setupBiometricPrompt() {
        val executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(
            this,
            executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    prefs.edit {
                        putBoolean(KEY_AUTHENTICATED, true)
                    }
                    Toast.makeText(
                        this@LoginActivity,
                        "Fingerprint verified",
                        Toast.LENGTH_SHORT
                    ).show()
                    goToHome()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(
                        this@LoginActivity,
                        "Biometric not recognized. Please try again or use password.",
                        Toast.LENGTH_SHORT
                    ).show()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Toast.makeText(
                        this@LoginActivity,
                        errString,
                        Toast.LENGTH_SHORT
                    ).show()
                    passwordEditText.requestFocus()
                }
            }
        )

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Sign in with fingerprint")
            .setSubtitle("Use your fingerprint for quick access")
            .setDescription("Authenticate with your fingerprint or use your password if needed")
            .setNegativeButtonText("Use password")
            .build()
    }

    private fun checkBiometricAvailabilityAndPrefill() {
        val biometricManager = BiometricManager.from(this)
        val canAuthenticate = biometricManager.canAuthenticate(
            BiometricManager.Authenticators.BIOMETRIC_WEAK
        )

        biometricButton.isEnabled =
            canAuthenticate == BiometricManager.BIOMETRIC_SUCCESS

        if (!biometricButton.isEnabled) {
            biometricButton.text = "Use password"
        }
    }

    private fun startBiometricAuth() {
        val biometricManager = BiometricManager.from(this)
        val canAuthenticate = biometricManager.canAuthenticate(
            BiometricManager.Authenticators.BIOMETRIC_WEAK
        )

        if (canAuthenticate == BiometricManager.BIOMETRIC_SUCCESS) {
            biometricPrompt.authenticate(promptInfo)
        } else {
            Toast.makeText(
                this,
                "Biometric authentication not available. Please use password.",
                Toast.LENGTH_SHORT
            ).show()
            passwordEditText.requestFocus()
        }
    }

    private fun performPasswordLogin() {
        val username = usernameEditText.text.toString().trim()
        val password = passwordEditText.text.toString().trim()

        if (username.isEmpty() || password.isEmpty()) {
            Toast.makeText(this, "Enter username and password", Toast.LENGTH_SHORT).show()
            return
        }

        val savedUsername = prefs.getString(KEY_USERNAME, null)
        val savedPassword = prefs.getString(KEY_PASSWORD, null)

        if (savedUsername == null || savedPassword == null) {
            prefs.edit {
                putString(KEY_USERNAME, username)
                putString(KEY_PASSWORD, password)
                putBoolean(KEY_AUTHENTICATED, true)
            }
            Toast.makeText(this, "Account saved. Welcome!", Toast.LENGTH_SHORT).show()
            goToHome()
            return
        }

        if (username == savedUsername && password == savedPassword) {
            prefs.edit {
                putBoolean(KEY_AUTHENTICATED, true)
            }
            Toast.makeText(this, "Login successful", Toast.LENGTH_SHORT).show()
            goToHome()
        } else {
            Toast.makeText(this, "Invalid username or password", Toast.LENGTH_SHORT).show()
        }
    }

    private fun goToHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }

    override fun onResume() {
        super.onResume()
        if (prefs.getBoolean(KEY_AUTHENTICATED, false)) {
            goToHome()
        }
    }
}

class HomeActivity : AppCompatActivity() {

    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_AUTHENTICATED = "key_authenticated"
    }

    private lateinit var prefs: SharedPreferences

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_home)

        prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        if (!prefs.getBoolean(KEY_AUTHENTICATED, false)) {
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }

        findViewById<Button>(R.id.logoutButton).setOnClickListener {
            prefs.edit {
                putBoolean(KEY_AUTHENTICATED, false)
            }
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }
    }
}